val pipeline = repository.observeJobs()
    .map { jobs -> jobs.filter(Job::isVisible) }
    .filter { jobs -> jobs.isNotEmpty() }

// Chưa chạy upstream
pipeline.collect { jobs -> render(jobs) }

val cards = jobs.map { list -> list.map(Job::toCard) }

val events = states.transform { state ->
    emit(AnalyticsEvent.StateSeen(state.name))
    if (state is UiState.Error) emit(AnalyticsEvent.ErrorSeen(state.code))
}

repository.observeJobs()
    .onEach { jobs -> metrics.recordResultCount(jobs.size) }
    .map { jobs -> jobs.map(Job::toCard) }
    .collect(::render)

repository.loadCards()
    .map<Cards, UiState> { UiState.Content(it) }
    .onStart { emit(UiState.Loading) }
    .onCompletion { cause -> logger.debug("cards completed: $cause") }

repository.observeJobs()
    .map { jobs -> jobs.map(Job::toCard) }
    .catch { error ->
        if (error is CancellationException) throw error
        emit(emptyList())
    }
    .collect { cards -> render(cards) }

fun observeVisibleJobs(): Flow<JobsUiState> =
    repository.observeJobs()
        .map { jobs -> jobs.filter(Job::isVisible) }
        .map<List<Job>, JobsUiState> { jobs ->
            if (jobs.isEmpty()) JobsUiState.Empty
            else JobsUiState.Content(jobs.map(Job::toCard))
        }
        .onStart { emit(JobsUiState.Loading) }
        .catch { error ->
            if (error is CancellationException) throw error
            emit(JobsUiState.Error(error.toUiText()))
        }
